import os
from collections import defaultdict

def get_usage_by_dir(path):
    usage = defaultdict(int)
    total_size = 0
    try:
        for root, dirs, files in os.walk(path):
            for f in files:
                filepath = os.path.join(root, f)
                size = os.path.getsize(filepath)
                usage[root] += size
                total_size += size
    except OSError as error:
